query:
SELECT p.id, p.status, p.mcpPending, p.retryCount, p.scheduledAt, p.publishedAt, LEFT(p.caption,60) as caption, p.createdAt 
FROM posts p 
ORDER BY p.createdAt DESC LIMIT 10;

